1	/**
2	 * Look-ahead scheduler using the Chris Wilson pattern:
3	 * setInterval fires every ~25ms, scheduling audio events
4	 * that fall within the next 100ms of AudioContext time.
5	 *
6	 * This runs on the main thread. The setInterval callback is lightweight
7	 * (just math + scheduling calls), so it doesn't block rendering.
8	 */
9	
10	import type { TransportClock } from "./transport-clock";
11	
12	export type SchedulerConfig = {
13	  intervalMs: number;
14	  lookAheadMs: number;
15	};
16	
17	export type LookAheadScheduler = {
18	  start(): void;
19	  stop(): void;
20	  readonly isRunning: boolean;
21	};
22	
23	const DEFAULT_CONFIG: SchedulerConfig = {
24	  intervalMs: 25,
25	  lookAheadMs: 100,
26	};
27	
28	export function createLookAheadScheduler(
29	  ctx: AudioContext,
30	  clock: TransportClock,
31	  config?: Partial<SchedulerConfig>,
32	  onTick?: (beatTime: number, beatNumber: number) => void,
33	): LookAheadScheduler {
34	  const intervalMs = config?.intervalMs ?? DEFAULT_CONFIG.intervalMs;
35	  const lookAheadSec =
36	    (config?.lookAheadMs ?? DEFAULT_CONFIG.lookAheadMs) / 1000;
37	
38	  let timerId: ReturnType<typeof setInterval> | null = null;
39	  let nextBeatTime = 0;
40	  let currentBeat = 0;
41	
42	  function syncToPosition(cursorSec: number): void {
43	    const spb = clock.getTempoMap().secondsPerBeat();
44	    const totalBeats = cursorSec / spb;
45	    const wholeBeat = Math.floor(totalBeats + 1e-9);
46	    const remainder = totalBeats - wholeBeat;
47	
48	    if (remainder < 1e-6) {
49	      // On a beat boundary — schedule this beat now
50	      currentBeat = wholeBeat;
51	      nextBeatTime = ctx.currentTime;
52	    } else {
53	      // Between beats — schedule next beat
54	      currentBeat = wholeBeat + 1;
55	      nextBeatTime = ctx.currentTime + (currentBeat * spb - cursorSec);
56	    }
57	  }
58	
59	  function advance(): void {
60	    if (clock.state !== "playing") return;
61	
62	    // Drive SAB cursor updates and detect loop wraps
63	    clock.updateCursor();
64	
65	    if (clock.didLoopWrap()) {
66	      syncToPosition(clock.getCursorSeconds());
67	    }
68	
69	    const scheduleUntil = ctx.currentTime + lookAheadSec;
70	    const spb = clock.getTempoMap().secondsPerBeat();
71	
72	    while (nextBeatTime < scheduleUntil) {
73	      onTick?.(nextBeatTime, currentBeat);
74	      currentBeat++;
75	      nextBeatTime += spb;
76	    }
77	  }
78	
79	  const scheduler: LookAheadScheduler = {
80	    get isRunning(): boolean {
81	      return timerId !== null;
82	    },
83	
84	    start(): void {
85	      if (timerId !== null) return;
86	
87	      // Phase-correct: sync beat position to current cursor
88	      syncToPosition(clock.getCursorSeconds());
89	
90	      timerId = setInterval(advance, intervalMs);
91	      advance();
92	    },
93	
94	    stop(): void {
95	      if (timerId !== null) {
96	        clearInterval(timerId);
97	        timerId = null;
98	      }
99	      nextBeatTime = 0;
100	      currentBeat = 0;
101	    },
102	  };
103	
104	  return scheduler;
105	}
