1	import { useCallback, useEffect, useRef, useState } from "react";
2	import {
3	  isCrossOriginIsolated,
4	  createAudioEngine,
5	  type AudioEngineContext,
6	} from "@audio/index";
7	import { AudioEngineProvider } from "@audio/audio-engine-provider";
8	import { CrossOriginError, ClickToStart, DawShell } from "@ui/index";
9	import { useDawStore } from "@state/index";
10	
11	export function App(): React.JSX.Element {
12	  const crossOriginOk = isCrossOriginIsolated();
13	  const [engine, setEngine] = useState<AudioEngineContext | null>(null);
14	  const engineRef = useRef<AudioEngineContext | null>(null);
15	  const setEngineStatus = useDawStore((s) => s.setEngineStatus);
16	
17	  const handleStart = useCallback((): void => {
18	    if (engineRef.current) return;
19	
20	    let newEngine: AudioEngineContext;
21	    try {
22	      newEngine = createAudioEngine();
23	    } catch {
24	      setEngineStatus("error");
25	      return;
26	    }
27	
28	    engineRef.current = newEngine;
29	    newEngine.resume().then(
30	      () => {
31	        if (engineRef.current !== newEngine) return;
32	        setEngineStatus("running");
33	        setEngine(newEngine);
34	      },
35	      () => {
36	        void newEngine.close();
37	        if (engineRef.current === newEngine) {
38	          engineRef.current = null;
39	        }
40	        setEngineStatus("error");
41	      },
42	    );
43	  }, [setEngineStatus]);
44	
45	  useEffect(() => {
46	    return () => {
47	      void engineRef.current?.close();
48	      engineRef.current = null;
49	    };
50	  }, []);
51	
52	  if (!crossOriginOk) {
53	    return <CrossOriginError />;
54	  }
55	
56	  if (engine === null) {
57	    return <ClickToStart onStart={handleStart} />;
58	  }
59	
60	  return (
61	    <AudioEngineProvider engine={engine}>
62	      <DawShell />
63	    </AudioEngineProvider>
64	  );
65	}
