1	import { useState, useEffect } from "react";
2	
3	const QUERY = "(prefers-reduced-motion: reduce)";
4	
5	export function useReducedMotion(): boolean {
6	  const [prefersReduced, setPrefersReduced] = useState<boolean>(
7	    () => window.matchMedia(QUERY).matches,
8	  );
9	
10	  useEffect(() => {
11	    const mql = window.matchMedia(QUERY);
12	    const handler = (e: { matches: boolean }): void => {
13	      setPrefersReduced(e.matches);
14	    };
15	    mql.addEventListener("change", handler);
16	    return (): void => {
17	      mql.removeEventListener("change", handler);
18	    };
19	  }, []);
20	
21	  return prefersReduced;
22	}
