1	/**
2	 * Reads cursor position from SharedArrayBuffer at 60fps via requestAnimationFrame.
3	 * Bypasses React state entirely (NFR-13) -- returns a ref that updates every frame.
4	 */
5	
6	import { useEffect, useRef } from "react";
7	import { TransportLayout } from "@audio/shared-buffer-layout";
8	
9	export function useTransportCursor(
10	  transportSAB: SharedArrayBuffer | null,
11	): React.RefObject<number> {
12	  const cursorRef = useRef(0);
13	
14	  useEffect(() => {
15	    if (transportSAB === null) return;
16	
17	    const view = new Float64Array(
18	      transportSAB,
19	      TransportLayout.CURSOR_SECONDS,
20	      1,
21	    );
22	    let rafId = 0;
23	
24	    function tick(): void {
25	      const val = view[0];
26	      if (val !== undefined) {
27	        cursorRef.current = val;
28	      }
29	      rafId = requestAnimationFrame(tick);
30	    }
31	
32	    rafId = requestAnimationFrame(tick);
33	    return () => {
34	      cancelAnimationFrame(rafId);
35	    };
36	  }, [transportSAB]);
37	
38	  return cursorRef;
39	}
