7	export function detectAudioFormat(header: Uint8Array): AudioFormat | null {
8	  if (header.length < 2) return null;
9	
10	  // FLAC: "fLaC"
11	  if (
12	    header.length >= 4 &&
13	    header[0] === 0x66 &&
14	    header[1] === 0x4c &&
15	    header[2] === 0x61 &&
16	    header[3] === 0x43
17	  ) {
18	    return "flac";
19	  }
20	
21	  // OGG: "OggS"
22	  if (
23	    header.length >= 4 &&
24	    header[0] === 0x4f &&
25	    header[1] === 0x67 &&
26	    header[2] === 0x67 &&
27	    header[3] === 0x53
28	  ) {
29	    return "ogg";
30	  }
31	
32	  // WAV: "RIFF" + 4 bytes + "WAVE"
33	  if (
34	    header.length >= 12 &&
35	    header[0] === 0x52 &&
36	    header[1] === 0x49 &&
37	    header[2] === 0x46 &&
38	    header[3] === 0x46 &&
39	    header[8] === 0x57 &&
40	    header[9] === 0x41 &&
41	    header[10] === 0x56 &&
42	    header[11] === 0x45
43	  ) {
44	    return "wav";
45	  }
46	
47	  // MP3: ID3v2 tag "ID3"
48	  if (
49	    header.length >= 3 &&
50	    header[0] === 0x49 &&
51	    header[1] === 0x44 &&
52	    header[2] === 0x33
53	  ) {
54	    return "mp3";
55	  }
56	
57	  // MP3: Frame sync 0xFF 0xFB / 0xFF 0xF3 / 0xFF 0xF2
58	  if (
59	    header[0] === 0xff &&
60	    (header[1] === 0xfb || header[1] === 0xf3 || header[1] === 0xf2)
61	  ) {
62	    return "mp3";
63	  }
64	
